CREATE PROCEDURE [dbo].[RPT_CLIENT_COLL_SEG_ANG_NEW] (@REPORT_DATE VARCHAR(11))    
AS    
    
DECLARE @FILENAME VARCHAR(200)     
DECLARE @CASHFILENAME VARCHAR(200)     
DECLARE @DATACASH VARCHAR(MAX)    
   
SELECT FILENAME=CLEARING_PAN+'_'+REPLACE(CONVERT(VARCHAR,PROCESS_DT,103),'/','')+'_01.csv',  
Date=REPLACE(CONVERT(VARCHAR,PROCESS_DT,103),'/','-'),  
CLEARING_PAN,TRADING_PAN,CP_CODE,CP_PAN,  
CLIENT_PAN=CASE WHEN ACCOUNT_TYPE='P' THEN '' ELSE CASE WHEN CLIENT_PAN LIKE '%[^0-9A-Za-z]%' OR LEN(CLIENT_PAN) <> '10' OR RIGHT(CLIENT_PAN, 1) LIKE '%[^A-Za-z]%' THEN 'NNNNN1111N'   
    ELSE CLIENT_PAN END END,  
ACCOUNT_TYPE,SEGMENT_INDICATOR,--MTOM=PARTY_CODE,  
MTOM=UPPER(REPLACE(REPLACE(PARTY_CODE,' ',''),'`','')),  
VDT_LEDGER,  
EDT_LEDGER,  
PEAK_LEDGER,  
BG_REC_TM,FD_REC_TM,APPROVED_SEC_CASH_REC_TM,APPROVED_SEC_NONCASH_REC_TM,  
NONAPPROVED_SEC_REC_TM,CC_APPROVED_COMM_REC_TM,OTHER_COLL_REC_TM,LIEU_EPI_LEDGER_CLTM,  
POOL_ACCOUNT_CLTM,CASH_RET_TM,BG_RET_TM,FD_RET_TM,APPROVED_SEC_CASH_RET_TM,  
APPROVED_SEC_NONCASH_RET_TM,NONAPPROVED_SEC_RET_TM,CC_APPROVED_COMM_RET_TM,OTHER_COLL_RET_TM,  
CASH_WCM,BG_WCM,FD_WCM,APPROVED_SEC_CASH_WCM,APPROVED_SEC_NONCASH_WCM,NONAPPROVED_SEC_RET_WCM,  
CC_APPROVED_COMM_WCM,OTHER_COLL_WCM,CASH_RET_WCM,BG_RET_CM,FD_RET_CM,APPROVED_SEC_CASH_RET_CM,  
APPROVED_SEC_NONCASH_RET_CM,NONAPPROVED_SEC_RET_RET_CM,CC_APPROVED_COMM_RET_CM,OTHER_COLL_RET_CM,  
CASH_WNCL,BG_WNCL,FD_WNCL,APPROVED_SEC_CASH_WNCL,APPROVED_SEC_NONCASH_WNCL,CC_APPROVED_COMM_WNCL,  
MTF_INDICATOR = CASE WHEN EXCHANGE = 'MTF' THEN 'MTF' ELSE 'NON MTF' END ,  
UNCLEAR_RECEIPT= isnull(UNCLEAR_RECEIPT, 0),GOV_SEC_TBILL_REC_BY_TM = isnull(GOV_SEC_TBILL_REC_BY_TM, 0),GOV_SEC_TBILL_RET_BY_TM = isnull(GOV_SEC_TBILL_RET_BY_TM, 0),GOV_SEC_TBILL_PLACED_BY_CM = isnull(GOV_SEC_TBILL_PLACED_BY_CM,0),GOV_SEC_TBILL_RET_BY_CM
 = isnull(GOV_SEC_TBILL_RET_BY_CM, 0),GOV_SEC_TBILL_PLACED_BY_NCL = isnull(GOV_SEC_TBILL_PLACED_BY_NCL, 0),  
BG_FUNDED_RET_WITH_CM = isnull(BG_FUNDED_RET_WITH_CM, 0),BG_NONFUNDED_RET_WITH_CM = isnull(BG_NONFUNDED_RET_WITH_CM, 0),BG_FUNDED_PLACED_WITH_NCL = isnull(BG_FUNDED_PLACED_WITH_NCL, 0),BG_NONFUNDED_PLACED_WITH_NCL = isnull(BG_NONFUNDED_PLACED_WITH_NCL, 0)
,SETTLEMENT_AMOUNT = isnull(SETTLEMENT_AMOUNT, 0),UNCLAIM_CL_FUNDS = isnull(UNCLAIM_CL_FUNDS, 'NA'),CASH_COLL_MTF_POSITION = ISNULL(CASH_COLL_MTF_POSITION, 0),
EXCHANGE,CLIENT_PAN_NCX = CLIENT_PAN  INTO #CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW
FROM CLIENT_COLLATERAL_REPORTING_DETAILS_NEW  WITH (NOLOCK)
WHERE PROCESS_DT=@REPORT_DATE  
--AND PARTY_CODE BETWEEN 'A' AND 'ZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZZ999999'  
ORDER BY 1, EXCHANGE, CLEARING_PAN, TRADING_PAN, CLIENT_PAN, SEGMENT_INDICATOR  

CREATE CLUSTERED INDEX EXCHIDX ON #CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW (EXCHANGE)
  
TRUNCATE TABLE ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG   
TRUNCATE TABLE CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW  


--BULK INSERT CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE FROM (SELECT * FROM OPENQUERY (AngelNSECM, 'EXEC MSAJAG.DBO.[RPT_CLIENT_COLL_SEG_MCX] ''JUN  1 2022'''))



--INSERT INTO #CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE EXEC MSAJAG.DBO.[RPT_CLIENT_COLL_SEG_NSE] @REPORT_DATE  
INSERT INTO MSAJAG.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW 
SELECT FILENAME,  
Date,  
CLEARING_PAN,TRADING_PAN,CP_CODE,CP_PAN,  
CLIENT_PAN,  
ACCOUNT_TYPE,SEGMENT_INDICATOR,--MTOM=PARTY_CODE,  
MTOM,  
VDT_LEDGER,  
EDT_LEDGER,  
PEAK_LEDGER,  
BG_REC_TM,FD_REC_TM,APPROVED_SEC_CASH_REC_TM,APPROVED_SEC_NONCASH_REC_TM,  
NONAPPROVED_SEC_REC_TM,CC_APPROVED_COMM_REC_TM,OTHER_COLL_REC_TM,LIEU_EPI_LEDGER_CLTM,  
POOL_ACCOUNT_CLTM,CASH_RET_TM,BG_RET_TM,FD_RET_TM,APPROVED_SEC_CASH_RET_TM,  
APPROVED_SEC_NONCASH_RET_TM,NONAPPROVED_SEC_RET_TM,CC_APPROVED_COMM_RET_TM,OTHER_COLL_RET_TM,  
CASH_WCM,BG_WCM,FD_WCM,APPROVED_SEC_CASH_WCM,APPROVED_SEC_NONCASH_WCM,NONAPPROVED_SEC_RET_WCM,  
CC_APPROVED_COMM_WCM,OTHER_COLL_WCM,CASH_RET_WCM,BG_RET_CM,FD_RET_CM,APPROVED_SEC_CASH_RET_CM,  
APPROVED_SEC_NONCASH_RET_CM,NONAPPROVED_SEC_RET_RET_CM,CC_APPROVED_COMM_RET_CM,OTHER_COLL_RET_CM,  
CASH_WNCL,BG_WNCL,FD_WNCL,APPROVED_SEC_CASH_WNCL,APPROVED_SEC_NONCASH_WNCL,CC_APPROVED_COMM_WNCL,
MTF_INDICATOR = CASE WHEN EXCHANGE = 'MTF' THEN 'MTF' ELSE 'NON MTF' END ,  
UNCLEAR_RECEIPT= isnull(UNCLEAR_RECEIPT, 0),
GOV_SEC_TBILL_REC_BY_TM = isnull(GOV_SEC_TBILL_REC_BY_TM, 0),
GOV_SEC_TBILL_RET_BY_TM = isnull(GOV_SEC_TBILL_RET_BY_TM, 0),
GOV_SEC_TBILL_PLACED_BY_CM = isnull(GOV_SEC_TBILL_PLACED_BY_CM,0),
GOV_SEC_TBILL_RET_BY_CM = isnull(GOV_SEC_TBILL_RET_BY_CM, 0),
GOV_SEC_TBILL_PLACED_BY_NCL = isnull(GOV_SEC_TBILL_PLACED_BY_NCL, 0),  
BG_FUNDED_RET_WITH_CM = isnull(BG_FUNDED_RET_WITH_CM, 0),
BG_NONFUNDED_RET_WITH_CM = isnull(BG_NONFUNDED_RET_WITH_CM, 0),
BG_FUNDED_PLACED_WITH_NCL = isnull(BG_FUNDED_PLACED_WITH_NCL, 0),
BG_NONFUNDED_PLACED_WITH_NCL = isnull(BG_NONFUNDED_PLACED_WITH_NCL, 0)
,SETTLEMENT_AMOUNT = isnull(SETTLEMENT_AMOUNT, 0),UNCLAIM_CL_FUNDS = isnull(UNCLAIM_CL_FUNDS, 'NA'),CASH_COLL_MTF_POSITION = ISNULL(CASH_COLL_MTF_POSITION, 0)
FROM #CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW 
WHERE EXCHANGE IN ('NSE','NSX','MTF')  

  
