--SELECT *,'NSE' FROM ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG WHERE CONVERT(DATE,[Date]) = CONVERT(DATE,@REPORT_DATE)  
  
