      FROM MSAJAG.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE_NEW  

SELECT @FILENAME = [FILENAME] FROM ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG     WHERE [FILENAME] <> ''  
    
SET @CASHFILENAME = 'J:\BACKOFFICE\EXPORT\NSE_' + @FILENAME --+'.CSV'    
SET @DATACASH = 'EXEC MASTER.DBO.XP_CMDSHELL ''BCP " SELECT DATAFILE FROM ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG ORDER BY SRNO ASC  " QUERYOUT ' + @CASHFILENAME+ ' -c -t"," -c -t"," -r"\n" -T'', NO_OUTPUT'    
  
